import { api } from './client'

export interface AvailabilityRule {
  id: string
  teacherId: string
  dayOfWeek: number
  startTime: string
  endTime: string
  slotDurationMin: number
  isActive: boolean
  validFrom: string | null
  validUntil: string | null
  createdAt: string
  updatedAt: string
}

export interface CreateAvailabilityPayload {
  dayOfWeek: number
  startTime: string
  endTime: string
  slotDurationMin?: number
  validFrom?: string
  validUntil?: string
  teacherId?: string
}

export interface HolidayDto {
  id: string
  date: string
  label: string
  teacherId: string | null
  isRecurring: boolean
  createdAt: string
}

export interface GenerateSlotsResult { created: number; skipped: number }

export function fetchMyAvailability(): Promise<AvailabilityRule[]> {
  return api.get<AvailabilityRule[]>('/availability/mine')
}

export function fetchTeacherAvailability(teacherId: string): Promise<AvailabilityRule[]> {
  return api.get<AvailabilityRule[]>(`/availability/teacher/${teacherId}`)
}

export function createAvailability(payload: CreateAvailabilityPayload): Promise<AvailabilityRule> {
  return api.post<AvailabilityRule>('/availability', payload)
}

export function updateAvailability(id: string, patch: Partial<CreateAvailabilityPayload> & { isActive?: boolean }): Promise<AvailabilityRule> {
  return api.patch<AvailabilityRule>(`/availability/${id}`, patch)
}

export function deleteAvailability(id: string): Promise<{ ok: boolean }> {
  return api.delete<{ ok: boolean }>(`/availability/${id}`)
}

export function fetchHolidays(from?: string, to?: string): Promise<HolidayDto[]> {
  const qs = new URLSearchParams()
  if (from) qs.set('from', from)
  if (to) qs.set('to', to)
  return api.get<HolidayDto[]>(`/availability/holidays?${qs.toString()}`)
}

export function createHoliday(date: string, label: string, teacherId?: string | null, isRecurring = false): Promise<HolidayDto> {
  return api.post<HolidayDto>('/availability/holidays', { date, label, teacherId: teacherId ?? null, isRecurring })
}

export function deleteHoliday(id: string): Promise<{ ok: boolean }> {
  return api.delete<{ ok: boolean }>(`/availability/holidays/${id}`)
}

export function generateSlots(from: string, to: string, teacherIds?: string[]): Promise<GenerateSlotsResult> {
  return api.post<GenerateSlotsResult>('/availability/generate', { from, to, teacherIds })
}
